import { Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Monday', icon: '☀️', high: 75, low: 62 },
    { day: 'Tuesday', icon: '☁️', high: 72, low: 60 },
    { day: 'Wednesday', icon: '🌧️', high: 68, low: 58 },
    { day: 'Thursday', icon: '⛅', high: 70, low: 61 },
    { day: 'Friday', icon: '☀️', high: 76, low: 64 },
  ],
}: Props) {
  // Get emoji for current condition
  const conditionEmojis: Record<string, string> = {
    Sunny: '☀️',
    Cloudy: '☁️',
    Rainy: '🌧️',
    Snowy: '❄️',
    Stormy: '⛈️',
    Foggy: '🌫️',
    'Partly Cloudy': '⛅',
    Clear: '🌙',
  };

  const currentEmoji = conditionEmojis[condition] || '☀️';

  const getDefaultDayName = (index: number): string => {
    const dayNum = index + 1;
    return 'Day ' + dayNum;
  };

  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        maxWidth: '400px',
        margin: '0 auto',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header: City + Unit */}
        <Row justify="between" align="center" gap={16}>
          <Text
            variant="h3"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {city}
          </Text>
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            °{unit}
          </Text>
        </Row>

        {/* Current Weather Section */}
        <Stack
          direction="vertical"
          gap={16}
          align="center"
          style={{ padding: '0 var(--ggui-spacing-4, 16px)' }}
        >
          {/* Weather Icon */}
          <div
            style={{
              fontSize: '72px',
              lineHeight: 1,
              height: '72px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            {currentEmoji}
          </div>

          {/* Condition Text */}
          <Text
            variant="h2"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
            align="center"
          >
            {condition}
          </Text>

          {/* Temperature (Large) */}
          <div
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              lineHeight: 1.2,
            }}
          >
            {temperature}°{unit}
          </div>

          {/* Condition Description */}
          <Text
            variant="body"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="center"
          >
            Partly sunny skies
          </Text>
        </Stack>

        {/* Humidity & Wind Metrics */}
        <Row
          direction="horizontal"
          gap={32}
          justify="around"
          align="stretch"
        >
          {/* Humidity */}
          <Stack direction="vertical" gap={8} align="center">
            <Text
              variant="label"
              weight="medium"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="h3"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={8} align="center">
            <Text
              variant="label"
              weight="medium"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text
              variant="h3"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {windSpeed} mph
            </Text>
          </Stack>
        </Row>

        {/* Divider */}
        <Divider orientation="horizontal" margin={16} />

        {/* 5-Day Forecast Strip */}
        <div
          style={{
            display: 'flex',
            flexDirection: 'row',
            gap: 'var(--ggui-spacing-2, 8px)',
            justifyContent: 'space-between',
            flexWrap: 'nowrap',
            overflowX: 'auto',
          }}
        >
          {forecast.map((day, index) => {
            const dayName = day.day || getDefaultDayName(index);
            const icon = day.icon || '❓';
            const high = day.high !== undefined ? day.high : '--';
            const low = day.low !== undefined ? day.low : '--';

            return (
              <div
                key={index}
                style={{
                  flex: '1 0 auto',
                  minWidth: '80px',
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  gap: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {/* Day Name */}
                <Text
                  variant="label"
                  weight="medium"
                  color="var(--ggui-color-onSurface, #18181b)"
                  align="center"
                >
                  {dayName}
                </Text>

                {/* Weather Icon */}
                <div
                  style={{
                    fontSize: '48px',
                    lineHeight: 1,
                    height: '48px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  {icon}
                </div>

                {/* High/Low Temps */}
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  {high}°/{low}°
                </Text>
              </div>
            );
          })}
        </div>
      </Stack>
    </Card>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, TextArea, RadioGroup, Checkbox, Button, Divider, Icon, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: SurveyData) => void | Promise<void>;
}

function ProgressBar({ currentStep }: { currentStep: number }) {
  const progress = ((currentStep + 1) / 5) * 100;
  return (
    <Stack direction="vertical" gap={8}>
      <Row justify="between" align="center">
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Step {currentStep + 1} of 5</Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="medium">{Math.round(progress)}%</Text>
      </Row>
      <div style={{ width: '100%', height: '4px', backgroundColor: 'var(--ggui-color-outlineVariant, #e4e4e7)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', overflow: 'hidden' }}>
        <div style={{ height: '100%', width: progress + '%', backgroundColor: 'var(--ggui-color-primary-500, #0ea5e9)', transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)' }} />
      </div>
    </Stack>
  );
}

function StepContent(props: any) {
  const { currentStep, formData, errors, featureOptions, satisfactionLabels, onFieldChange, onNameChange, onEmailChange } = props;
  const { motionEnabled } = useMotion();
  const stepAnimation = motionEnabled ? { animation: animation.slideInUp } : {};

  if (currentStep === 0) {
    return (
      <Stack direction="vertical" gap={16} style={stepAnimation}>
        <Text variant="h3" color="var(--ggui-color-onSurface)">Let&apos;s start with your details</Text>
        <Input label="Full Name" placeholder="John Doe" value={formData.name} onChange={onNameChange} required error={errors.name} />
        <Input label="Email Address" type="email" placeholder="john@example.com" value={formData.email} onChange={onEmailChange} required error={errors.email} />
      </Stack>
    );
  }
  if (currentStep === 1) {
    return (
      <Stack direction="vertical" gap={16} style={stepAnimation}>
        <Text variant="h3" color="var(--ggui-color-onSurface)">How satisfied are you with our product?</Text>
        <RadioGroup value={formData.satisfaction} onChange={(v) => onFieldChange('satisfaction', v)} options={satisfactionLabels.map((label: string, i: number) => ({ value: String(i + 1), label }))} direction="vertical" />
      </Stack>
    );
  }
  if (currentStep === 2) {
    return (
      <Stack direction="vertical" gap={16} style={stepAnimation}>
        <Text variant="h3" color="var(--ggui-color-onSurface)">Which features interest you most?</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" weight="normal">Select all that apply</Text>
        <Stack direction="vertical" gap={12}>
          {featureOptions.map((option: string) => (
            <Checkbox key={option} label={option} checked={formData.features.includes(option)} onChange={(checked) => {
              if (checked) {
                onFieldChange('features', [...formData.features, option]);
              } else {
                onFieldChange('features', formData.features.filter((f: string) => f !== option));
              }
            }} />
          ))}
        </Stack>
      </Stack>
    );
  }
  if (currentStep === 3) {
    return (
      <Stack direction="vertical" gap={16} style={stepAnimation}>
        <Text variant="h3" color="var(--ggui-color-onSurface)">Any additional feedback?</Text>
        <Stack direction="vertical" gap={8}>
          <TextArea label="Comments" placeholder="Tell us anything else you'd like us to know..." value={formData.comments} onChange={(v) => onFieldChange('comments', v)} rows={5} maxLength={500} />
          <Row justify="end"><Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{formData.comments.length}/500 characters</Text></Row>
        </Stack>
      </Stack>
    );
  }
  return (
    <Stack direction="vertical" gap={16} style={stepAnimation}>
      <Text variant="h3" color="var(--ggui-color-onSurface)">Review Your Answers</Text>
      <Divider margin={12} />
      <Stack direction="vertical" gap={12}>
        <Row align="start" justify="between"><Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">Name:</Text><Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{formData.name}</Text></Row>
        <Divider margin={8} />
        <Row align="start" justify="between"><Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">Email:</Text><Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text></Row>
        <Divider margin={8} />
        <Row align="start" justify="between"><Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">Satisfaction:</Text><Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{satisfactionLabels[parseInt(formData.satisfaction, 10) - 1]}</Text></Row>
        <Divider margin={8} />
        <Row align="start" justify="between"><Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">Features:</Text><Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}</Text></Row>
        <Divider margin={8} />
        <Row align="start" justify="between"><Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">Comments:</Text><Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{formData.comments || 'None provided'}</Text></Row>
      </Stack>
    </Stack>
  );
}

function SubmitResult({ result }: { result: { success: boolean; message: string } | null }) {
  if (!result) return null;
  return (
    <div style={{ padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', backgroundColor: result.success ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-error-50, #fef2f2)', border: '1px solid ' + (result.success ? 'var(--ggui-color-success-200, #dcfce7)' : 'var(--ggui-color-error-200, #fecaca)') }}>
      <Text variant="body" color={result.success ? 'var(--ggui-color-success-700, #15803d)' : 'var(--ggui-color-error-700, #b91c1c)'} weight="medium">{result.message}</Text>
    </div>
  );
}

function Navigation(props: any) {
  const { currentStep, isSubmitting, isStep1Valid, onNext, onBack, onSubmit } = props;
  return (
    <Row justify="between" gap={12}>
      {currentStep > 0 ? <Button variant="outline" onClick={onBack} disabled={isSubmitting} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button> : <div />}
      {currentStep < 4 ? <Button variant="primary" onClick={onNext} disabled={currentStep === 0 ? !isStep1Valid : isSubmitting} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button> : <Button variant="primary" onClick={onSubmit} disabled={isSubmitting} loading={isSubmitting} leftIcon={isSubmitting ? undefined : <Icon name="check" size={16} />}>{isSubmitting ? 'Submitting...' : 'Submit Survey'}</Button>}
    </Row>
  );
}

export default function MultiStepSurvey({ featureOptions = ['Analytics', 'Real-time Reporting', 'Data Export', 'Custom Dashboards', 'API Access'], satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'], onSubmit }: Props) {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<SurveyData>({ name: '', email: '', satisfaction: '', features: [], comments: '' });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitResult, setSubmitResult] = useState<{ success: boolean; message: string } | null>(null);

  const validateEmail = (value: string): string => {
    if (!value) return 'Email is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return 'Please enter a valid email format';
    return '';
  };

  const validateName = (value: string): string => {
    if (!value) return 'Name is required';
    if (value.trim().length < 2) return 'Name must be at least 2 characters';
    return '';
  };

  const updateField = (field: keyof SurveyData, value: unknown) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) setErrors((prev) => ({ ...prev, [field]: '' }));
  };

  const handleNameChange = (value: string) => {
    updateField('name', value);
    if (value) setErrors((prev) => ({ ...prev, name: validateName(value) }));
  };

  const handleEmailChange = (value: string) => {
    updateField('email', value);
    if (value) setErrors((prev) => ({ ...prev, email: validateEmail(value) }));
  };

  const validateStep1 = (): boolean => {
    const nameError = validateName(formData.name);
    const emailError = validateEmail(formData.email);
    if (nameError || emailError) {
      setErrors({ name: nameError, email: emailError });
      return false;
    }
    return true;
  };

  const handleNext = () => {
    if (currentStep === 0 && !validateStep1()) return;
    if (currentStep < 4) {
      setCurrentStep((prev) => prev + 1);
      setSubmitResult(null);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep((prev) => prev - 1);
      setSubmitResult(null);
    }
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitResult(null);
    try {
      if (onSubmit) await onSubmit(formData);
      setSubmitResult({ success: true, message: 'Survey submitted successfully!' });
      setTimeout(() => {
        setCurrentStep(0);
        setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' });
        setErrors({});
      }, 2000);
    } catch (error) {
      setSubmitResult({ success: false, message: 'Failed to submit survey. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  const isStep1Valid = !errors.name && !errors.email && formData.name && formData.email;

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md" padding={24} center>
        <Card padding={24} shadow="md" border>
          <Stack direction="vertical" gap={24} role="form" aria-label="Customer survey form">
            <Stack direction="vertical" gap={8}>
              <Text variant="h2" color="var(--ggui-color-onSurface)" align="center">Customer Survey</Text>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">Help us improve by sharing your feedback</Text>
            </Stack>
            <ProgressBar currentStep={currentStep} />
            <Divider margin={8} />
            <StepContent currentStep={currentStep} formData={formData} errors={errors} featureOptions={featureOptions} satisfactionLabels={satisfactionLabels} onFieldChange={updateField} onNameChange={handleNameChange} onEmailChange={handleEmailChange} />
            <SubmitResult result={submitResult} />
            <Divider margin={8} />
            <Navigation currentStep={currentStep} isSubmitting={isSubmitting} isStep1Valid={isStep1Valid} onNext={handleNext} onBack={handleBack} onSubmit={handleSubmit} />
          </Stack>
        </Card>
      </Container>
    </>
  );
}

import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

interface StockCardProps {
  stock: Stock;
  index: number;
  motionEnabled: boolean;
}

// Format price to 2 decimal places
const formatPrice = (value: number): string => {
  return value.toFixed(2);
};

// Format timestamp for display
const formatTimestamp = (iso: string | undefined): string => {
  if (!iso) return 'Never';
  try {
    const date = new Date(iso);
    return date.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    });
  } catch {
    return iso;
  }
};

// Get animation delay based on index
const getAnimationDelay = (index: number, motionEnabled: boolean): string => {
  if (!motionEnabled) return '0ms';
  const delayValue = index * 50;
  return delayValue + 'ms';
};

// Stock card component
function StockCard({ stock, index, motionEnabled }: StockCardProps) {
  const isPositive = (stock.changePercent ?? 0) >= 0;
  const changeColor = isPositive
    ? 'var(--ggui-color-success-500, #22c55e)'
    : 'var(--ggui-color-error-500, #ef4444)';
  const borderColor = isPositive
    ? 'var(--ggui-color-success-200, #dcfce7)'
    : 'var(--ggui-color-error-200, #fee2e2)';

  const slideInAnimation = motionEnabled ? animation.slideInUp : 'none';
  const animDelay = getAnimationDelay(index, motionEnabled);
  const priceStr = formatPrice(stock.price ?? 0);
  const changeStr = formatPrice(stock.change ?? 0);
  const percentStr = formatPrice(stock.changePercent ?? 0);

  return (
    <Card
      padding={16}
      shadow="sm"
      border
      style={{
        borderColor: borderColor,
        borderWidth: '1px',
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        animation: slideInAnimation,
        animationDelay: animDelay,
        transition: transition.colors,
      }}
    >
      <Row
        direction="horizontal"
        justify="between"
        align="center"
        gap={12}
      >
        {/* Left: Ticker & Company */}
        <Stack direction="vertical" gap={4}>
          <Text
            variant="h3"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {stock.symbol || 'N/A'}
          </Text>
          <Text
            variant="body"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {stock.name || 'Unknown'}
          </Text>
        </Stack>

        {/* Right: Price & Change */}
        <Stack direction="vertical" gap={2} align="end">
          <Text
            variant="h3"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            $
            {priceStr}
          </Text>

          <Row
            direction="horizontal"
            gap={4}
            align="center"
            justify="end"
          >
            <span
              aria-label={isPositive ? 'price up' : 'price down'}
              style={{
                color: changeColor,
                fontSize: 'var(--ggui-font-size-base, 16px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
              }}
            >
              {isPositive ? '▲' : '▼'}
            </span>
            <Text
              variant="body"
              weight="semibold"
              color={changeColor}
            >
              $
              {changeStr}
            </Text>
            <Text
              variant="body"
              weight="semibold"
              color={changeColor}
            >
              {isPositive ? '+' : ''}
              {percentStr}
              %
            </Text>
          </Row>
        </Stack>
      </Row>
    </Card>
  );
}

export default function StockTickerDashboard({
  stocks: initialStocks,
  lastUpdated: initialTimestamp,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Stock[]>(initialStocks || []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(
    initialTimestamp
  );
  const [connectionStatus, setConnectionStatus] = useState<'idle' | 'connecting' | 'connected' | 'error'>(
    'idle'
  );
  const { motionEnabled } = useMotion();

  // Set up event listener for live data updates
  useEffect(() => {
    setConnectionStatus('connecting');

    const handler = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail?.stocks && Array.isArray(customEvent.detail.stocks)) {
        setLiveStocks(customEvent.detail.stocks);
        setConnectionStatus('connected');
        if (customEvent.detail.timestamp) {
          setLastUpdated(customEvent.detail.timestamp);
        } else {
          setLastUpdated(new Date().toISOString());
        }
      }
    };

    // Listen to custom event on document
    const target = typeof document !== 'undefined' ? document : null;
    if (target) {
      target.addEventListener('ggui:agent-data', handler);

      const timer = setTimeout(() => {
        if (connectionStatus === 'connecting' && initialStocks && initialStocks.length > 0) {
          setConnectionStatus('connected');
        }
      }, 3000);

      return () => {
        target.removeEventListener('ggui:agent-data', handler);
        clearTimeout(timer);
      };
    }

    return undefined;
  }, []);

  // Use live stocks if available, fallback to initial prop
  const displayStocks = liveStocks.length > 0 ? liveStocks : initialStocks || [];
  const timestampDisplay = formatTimestamp(lastUpdated);

  // Show loading state if no stocks and connecting
  if (displayStocks.length === 0 && connectionStatus === 'connecting') {
    return (
      <Container maxWidth="lg" padding={24}>
        <Stack direction="vertical" gap={24}>
          <Card
            padding={16}
            shadow="sm"
            border
            style={{
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            }}
          >
            <Row direction="horizontal" justify="between" align="center">
              <Text
                variant="h2"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                Market Watch
              </Text>
              <Stack direction="vertical" gap={4} align="end">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Status
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Connecting...
                </Text>
              </Stack>
            </Row>
          </Card>
          <div style={{ textAlign: 'center', padding: 'var(--ggui-spacing-12, 48px) 0' }}>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Connecting to live data...
            </Text>
          </div>
        </Stack>
      </Container>
    );
  }

  // Show empty state if no stocks at all
  if (displayStocks.length === 0) {
    return (
      <Container maxWidth="lg" padding={24}>
        <Stack direction="vertical" gap={24}>
          <Card
            padding={16}
            shadow="sm"
            border
            style={{
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            }}
          >
            <Row direction="horizontal" justify="between" align="center">
              <Text
                variant="h2"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                Market Watch
              </Text>
              <Stack direction="vertical" gap={4} align="end">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Last Updated
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {timestampDisplay}
                </Text>
              </Stack>
            </Row>
          </Card>
          <div style={{ textAlign: 'center', padding: 'var(--ggui-spacing-12, 48px) 0' }}>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              No stocks available
            </Text>
          </div>
        </Stack>
      </Container>
    );
  }

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="lg" padding={24}>
        <Stack direction="vertical" gap={24}>
          {/* Header */}
          <Card
            padding={16}
            shadow="sm"
            border
            style={{
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            }}
          >
            <Row
              direction="horizontal"
              justify="between"
              align="center"
              gap={16}
            >
              <Text
                variant="h2"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                Market Watch
              </Text>
              <Stack direction="vertical" gap={4} align="end">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Last Updated
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  {timestampDisplay}
                </Text>
              </Stack>
            </Row>
          </Card>

          {/* Stock Grid */}
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {displayStocks.map((stock, index) => (
              <StockCard
                key={stock.symbol || index}
                stock={stock}
                index={index}
                motionEnabled={motionEnabled}
              />
            ))}
          </div>
        </Stack>
      </Container>
    </>
  );
}

import { Container, Card, Box, Stack, Row, Text, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const c = condition.toLowerCase();
  if (c.includes('sunny') || c === 'clear') return '☀️';
  if (c.includes('partly cloudy') || c.includes('partly')) return '⛅';
  if (c.includes('thunderstorm') || c.includes('thunder')) return '⛈️';
  if (c.includes('drizzle')) return '🌦️';
  if (c.includes('cloudy') || c.includes('overcast')) return '☁️';
  if (c.includes('rain')) return '🌧️';
  if (c.includes('snow')) return '🌨️';
  if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
  if (c.includes('wind')) return '💨';
  return '🌤️';
}

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = 'C',
