          aria-label={regionLabel}
          style={{
            animation: motionEnabled ? animation.fadeIn : 'none',
          }}
        >
          <Card padding={0} shadow="md" border={true}>
            <Stack direction="vertical" gap={0}>

              {/* ── HEADER: Branded gradient ── */}
              <Box
                padding={0}
