import { useState } from 'react';
import {
  Container, Card, Box, Stack, Row, Text, Input, TextArea,
  RadioGroup, Checkbox, Button, Divider, Badge, Icon, Spacer, Toast,
  MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers as a structured object */
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: string;
    satisfactionLabel: string;
    selectedFeatures: string[];
    comments: string;
  }) => void | Promise<void>;
}

const TOTAL_STEPS = 5;
const STEP_NAMES = ['Personal Info', 'Satisfaction', 'Features', 'Comments', 'Review'];

export default function GeneratedComponent({
  featureOptions = ['Dark Mode', 'API Access', 'Analytics Dashboard', 'Team Collaboration', 'Custom Integrations'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState(0);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [animKey, setAnimKey] = useState(0);

  const validateName = (value: string): string =>
    !value.trim() ? 'Name is required' : '';

  const validateEmail = (value: string): string => {
    if (!value.trim()) return 'Email is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return 'Please enter a valid email';
    return '';
  };

  const handleNameChange = (value: string) => {
    setName(value);
    if (touched.name) setErrors(prev => ({ ...prev, name: validateName(value) }));
  };

  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (touched.email) setErrors(prev => ({ ...prev, email: validateEmail(value) }));
  };

  const touchName = () => {
    setTouched(prev => ({ ...prev, name: true }));
    setErrors(prev => ({ ...prev, name: validateName(name) }));
  };

  const touchEmail = () => {
    setTouched(prev => ({ ...prev, email: true }));
    setErrors(prev => ({ ...prev, email: validateEmail(email) }));
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setSelectedFeatures(prev =>
      checked ? [...prev, feature] : prev.filter(f => f !== feature)
    );
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) setComments(value);
  };

  const isStepValid = (s: number): boolean => {
    switch (s) {
      case 0: return !validateName(name) && !validateEmail(email);
      case 1: return satisfaction !== '';
      default: return true;
    }
  };

  const goNext = () => {
    if (step === 0) {
      const nameErr = validateName(name);
      const emailErr = validateEmail(email);
      setTouched({ name: true, email: true });
      setErrors(prev => ({ ...prev, name: nameErr, email: emailErr }));
      if (nameErr || emailErr) return;
    }
    if (step < TOTAL_STEPS - 1) {
      setStep(s => s + 1);
      setAnimKey(k => k + 1);
    }
  };

  const goBack = () => {
    if (step > 0) {
      setStep(s => s - 1);
      setAnimKey(k => k + 1);
    }
  };

  const handleSubmit = async () => {
    if (!onSubmit) return;
    setIsSubmitting(true);
    setSubmitStatus('idle');
    try {
      const idx = parseInt(satisfaction, 10) - 1;
      await onSubmit({
        name,
        email,
        satisfaction,
        satisfactionLabel: satisfactionLabels[idx] || '',
        selectedFeatures,
        comments,
      });
      setSubmitStatus('success');
    } catch {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const progressPercent = ((step + 1) / TOTAL_STEPS) * 100;

  // Build radio options using string concatenation (no template literals with expressions)
  const satisfactionOptions = satisfactionLabels.map((label, i) => {
    const num = i + 1;
    const numStr = String(num);
    return { value: numStr, label: numStr + ' \u2014 ' + label };
  });

  const renderProgressBar = () => (
    <Stack direction="vertical" gap={8}>
      <Row justify="between" align="center">
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {'Step ' + (step + 1) + ' of ' + TOTAL_STEPS}
        </Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {STEP_NAMES[step]}
        </Text>
      </Row>
      <div
        role="progressbar"
        aria-valuenow={step + 1}
        aria-valuemin={1}
        aria-valuemax={TOTAL_STEPS}
        aria-label="Survey progress"
        style={{ width: '100%', height: 8, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: 'var(--ggui-color-outlineVariant, #e4e4e7)', overflow: 'hidden' }}
      >
        <div style={{ width: progressPercent + '%', height: '100%', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: 'linear-gradient(90deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-600, #0284c7))', transition: motionEnabled ? 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)' : 'none' }} />
      </div>
    </Stack>
  );

  const renderStepIndicator = () => (
    <Row gap={4} justify="center" align="start" wrap>
      {STEP_NAMES.map((stepName, i) => {
        const isCompleted = i < step;
        const isActive = i === step;
        return (
          <Stack key={stepName} direction="vertical" align="center" gap={4}>
            <div
              aria-current={isActive ? 'step' : undefined}
              style={{
                width: 32, height: 32,
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 'var(--ggui-font-size-sm, 14px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                background: isCompleted || isActive ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                color: isCompleted || isActive ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                border: isActive ? '2px solid var(--ggui-color-primary-400, #38bdf8)' : isCompleted ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                transition: motionEnabled ? transition.colors : 'none',
                flexShrink: 0,
              }}
            >
              {isCompleted ? <Icon name="check" size={16} color="var(--ggui-color-primary-50, #f0f9ff)" /> : i + 1}
            </div>
            <Text variant="caption" color={isActive ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'} weight={isActive ? 'semibold' : 'normal'}>
              {stepName}
            </Text>
          </Stack>
        );
      })}
    </Row>
  );

  const nameInputError = touched.name ? errors.name : undefined;
  const emailInputError = touched.email ? errors.email : undefined;

  const renderStep0 = () => (
    <Stack direction="vertical" gap={16}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Personal Information</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please tell us a bit about yourself.</Text>
      </Stack>
      <div onBlur={touchName}>
        <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} required error={nameInputError} helperText="Your name as you would like to be addressed" />
      </div>
      <div onBlur={touchEmail}>
        <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={handleEmailChange} required error={emailInputError} helperText="We will never share your email with anyone" />
      </div>
    </Stack>
  );

  const renderStep1 = () => (
    <Stack direction="vertical" gap={16}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Satisfaction Rating</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">How satisfied are you with our product or service?</Text>
      </Stack>
      <RadioGroup label="Your Rating" value={satisfaction} onChange={setSatisfaction} options={satisfactionOptions} direction="vertical" />
    </Stack>
  );

  const renderStep2 = () => (
    <Stack direction="vertical" gap={16}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Feature Interests</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Which features are you most interested in? (Select all that apply)</Text>
      </Stack>
      <Stack direction="vertical" gap={12}>
        {featureOptions.map(feature => (
          <Checkbox key={feature} label={feature} checked={selectedFeatures.includes(feature)} onChange={(checked) => handleFeatureToggle(feature, checked)} />
        ))}
      </Stack>
    </Stack>
  );

  const renderStep3 = () => (
    <Stack direction="vertical" gap={16}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Additional Comments</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Is there anything else you would like to share? (Optional)</Text>
      </Stack>
      <TextArea label="Comments" placeholder="Share your thoughts, suggestions, or feedback..." value={comments} onChange={handleCommentsChange} rows={5} maxLength={500} />
      <Text variant="caption" align="right" color={comments.length >= 480 ? 'var(--ggui-color-error-500, #ef4444)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'} weight={comments.length >= 480 ? 'semibold' : 'normal'}>
        {comments.length + '/500 characters'}
      </Text>
    </Stack>
  );

  const renderReview = () => {
    const idx = parseInt(satisfaction, 10) - 1;
    const satisfactionText = satisfactionLabels[idx] || 'Not selected';
    return (
      <Stack direction="vertical" gap={16} aria-live="polite">
        <Stack direction="vertical" gap={4}>
          <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Review Your Answers</Text>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please review your responses before submitting.</Text>
        </Stack>
        <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius="var(--ggui-shape-radius-md, 8px)">
          <Stack direction="vertical" gap={10}>
            <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">Personal Information</Text>
            <Row gap={8} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="semibold">Name:</Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{name}</Text>
            </Row>
            <Row gap={8} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="semibold">Email:</Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{email}</Text>
            </Row>
          </Stack>
        </Box>
        <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius="var(--ggui-shape-radius-md, 8px)">
          <Stack direction="vertical" gap={10}>
            <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">Satisfaction Rating</Text>
            <Row gap={8} align="center">
              <Badge variant="primary" size="sm">{satisfaction || '\u2014'}</Badge>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{satisfactionText}</Text>
            </Row>
          </Stack>
        </Box>
        <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius="var(--ggui-shape-radius-md, 8px)">
          <Stack direction="vertical" gap={10}>
            <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">Feature Interests</Text>
            {selectedFeatures.length > 0 ? (
              <Row gap={8} wrap>
                {selectedFeatures.map(feature => (
                  <Badge key={feature} variant="primary" size="sm">{feature}</Badge>
                ))}
              </Row>
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
            )}
          </Stack>
        </Box>
        <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius="var(--ggui-shape-radius-md, 8px)">
          <Stack direction="vertical" gap={10}>
            <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">Additional Comments</Text>
            <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{comments || '\u2014'}</Text>
          </Stack>
        </Box>
      </Stack>
    );
  };

  const renderStepContent = () => {
    switch (step) {
      case 0: return renderStep0();
      case 1: return renderStep1();
      case 2: return renderStep2();
      case 3: return renderStep3();
      case 4: return renderReview();
      default: return null;
    }
  };

  const isLastStep = step === TOTAL_STEPS - 1;
  const canGoNext = isStepValid(step);
  const stepLabel = 'Step ' + (step + 1) + ' of ' + TOTAL_STEPS + ': ' + STEP_NAMES[step];

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md">
        <Card padding={24} shadow="md">
          <Stack direction="vertical" gap={24}>
            <Text variant="h2" align="center" color="var(--ggui-color-onSurface, #18181b)">Survey</Text>
            {renderProgressBar()}
            {renderStepIndicator()}
            <Divider />
            <div key={animKey} aria-label={stepLabel} style={{ animation: motionEnabled ? animation.fadeIn : 'none', minHeight: 200 }}>
              {renderStepContent()}
            </div>
            <Divider />
            <Row justify="between" align="center">
              {step > 0 ? (
                <Button variant="outline" onClick={goBack} leftIcon={<Icon name="chevron-left" size={16} />} disabled={isSubmitting}>Back</Button>
              ) : (
                <Spacer size={1} />
              )}
              {!isLastStep ? (
                <Button variant="primary" onClick={goNext} disabled={!canGoNext} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit} disabled={isSubmitting} loading={isSubmitting} leftIcon={!isSubmitting ? <Icon name="check" size={16} /> : undefined}>
                  {isSubmitting ? 'Submitting...' : 'Submit Survey'}
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Container>
      <Toast message="Your survey has been submitted successfully. Thank you for your feedback!" variant="success" title="Survey Submitted" visible={submitStatus === 'success'} onClose={() => setSubmitStatus('idle')} duration={5000} />
      <Toast message="Something went wrong while submitting your survey. Please try again." variant="error" title="Submission Failed" visible={submitStatus === 'error'} onClose={() => setSubmitStatus('idle')} duration={5000} />
    </>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import {
  Container, Card, Stack, Row, Text, Badge,
  Input, Button, Icon, MotionKeyframes, useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface MessageGroup {
  sender: string;
  messages: Message[];
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

function formatTime(isoString?: string): string {
  if (!isoString) return '';
  try {
    return new Date(isoString).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
  } catch {
    return '';
  }
}

function groupMessages(msgs: Message[]): MessageGroup[] {
  const groups: MessageGroup[] = [];
  for (const msg of msgs) {
    const sender = msg.sender || 'Unknown';
    const last = groups[groups.length - 1];
    if (last && last.sender === sender) {
      last.messages.push(msg);
    } else {
      groups.push({ sender, messages: [msg] });
    }
  }
  return groups;
}

export default function GeneratedComponent({
  title = 'Chat Room',
  currentUser = 'You',
  participantCount,
  messages = [
    { sender: 'Alice', text: 'Hey there! How are you doing?', timestamp: '2024-01-15T10:30:00Z' },
    { sender: 'Alice', text: 'Did you see the latest update?', timestamp: '2024-01-15T10:30:30Z' },
    { sender: 'You', text: "Hi Alice! I'm doing great, thanks!", timestamp: '2024-01-15T10:31:00Z' },
    { sender: 'You', text: 'Yes, the new features look amazing.', timestamp: '2024-01-15T10:31:15Z' },
    { sender: 'Alice', text: 'Right? I especially like the real-time sync.', timestamp: '2024-01-15T10:32:00Z' },
  ],
  onSendMessage,
}: Props) {
  const [inputText, setInputText] = useState('');
  const [allMessages, setAllMessages] = useState<Message[]>(messages);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const rootRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => { setAllMessages(messages); }, [messages]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // Stream Contract: listen for ggui:agent-data on the root element
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const handler = (e: Event) => {
      const d = (e as CustomEvent).detail;
      if (d?.text) {
        setAllMessages(prev => [...prev, {
          sender: d.sender || 'Agent',
          text: d.text,
          timestamp: d.timestamp || new Date().toISOString(),
        }]);
      }
    };
    el.addEventListener('ggui:agent-data', handler);
    return () => el.removeEventListener('ggui:agent-data', handler);
  }, []);

  // Action Contract: sendMessage
  const handleSend = useCallback(() => {
    const trimmed = inputText.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    setAllMessages(prev => [...prev, { sender: currentUser, ...payload }]);
    onSendMessage?.(payload);
    setInputText('');
  }, [inputText, currentUser, onSendMessage]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  }, [handleSend]);

  const grouped = groupMessages(allMessages);
  const canSend = inputText.trim().length > 0;

  return (
    <div ref={rootRef}>
      <Container maxWidth="md" padding={0}>
        <MotionKeyframes />
        <Card shadow="md" border padding={0}>
          <div style={{ display: 'flex', flexDirection: 'column', height: 520 }}>

            {/* HEADER */}
            <div style={{
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              padding: 'var(--ggui-spacing-4, 16px)',
              flexShrink: 0,
            }}>
              <Row align="center" justify="between">
                <Text variant="h3" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">
                  {title}
                </Text>
                {participantCount !== undefined && (
                  <Badge variant="primary" size="sm" pill>
                    <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                      <Icon name="user" size={12} />
                      {participantCount}
                    </span>
                  </Badge>
                )}
              </Row>
            </div>

            {/* MESSAGE LIST */}
            <div
              role="log"
              aria-label="Message history"
              aria-live="polite"
              style={{
                flex: 1,
                overflowY: 'auto',
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-surface, #fafafa)',
              }}
            >
              <Stack gap={16}>
                {grouped.map((group, gi) => {
                  const isOwn = group.sender === currentUser;
                  const groupKey = 'grp-' + String(gi);
                  return (
                    <div
                      key={groupKey}
                      style={{
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: isOwn ? 'flex-end' : 'flex-start',
                        gap: 'var(--ggui-spacing-1, 4px)',
                      }}
                    >
                      {!isOwn && (
                        <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {group.sender}
                        </Text>
                      )}
                      {group.messages.map((msg, mi) => {
                        const msgKey = 'm-' + String(gi) + '-' + String(mi);
                        const isLast = mi === group.messages.length - 1;
                        return (
                          <div
                            key={msgKey}
                            style={{
                              maxWidth: '75%',
                              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                              borderRadius: isOwn
                                ? 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px)'
                                : 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px)',
                              backgroundColor: isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                              boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                              animation: motionEnabled ? animation.fadeIn : 'none',
                            }}
                          >
                            <Text
                              variant="body"
                              color={isOwn ? 'var(--ggui-color-neutral-50, #f9fafb)' : 'var(--ggui-color-onSurface, #18181b)'}
                            >
                              {msg.text}
                            </Text>
                            {isLast && (
                              <div style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
                                <Text
                                  variant="caption"
                                  color={isOwn ? 'var(--ggui-color-primary-200, #bae6fd)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                                >
                                  {formatTime(msg.timestamp)}
                                </Text>
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  );
                })}
                <div ref={messagesEndRef} />
              </Stack>
            </div>

            {/* INPUT AREA */}
            <div
              onKeyDown={handleKeyDown}
              style={{
                borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                flexShrink: 0,
              }}
            >
              <Text as="label" htmlFor="chat-input" variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Message
              </Text>
              <Input label="Message" placeholder="Type a message..." value={inputText} onChange={setInputText} />
              <div style={{ marginTop: 'var(--ggui-spacing-2, 8px)', display: 'flex', justifyContent: 'flex-end' }}>
                <Button
                  variant="primary"
                  onClick={handleSend}
                  disabled={!canSend}
                  aria-label="Send message"
                  leftIcon={
                    <svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor" aria-hidden="true">
                      <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
                    </svg>
                  }
                >
                  Send
                </Button>
              </div>
            </div>

          </div>
        </Card>
      </Container>
    </div>
  );
}

