import { useState, useEffect } from 'react';
import { Container, Card, Box, Stack, Row, Text, Badge, Spacer, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface StockItem { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number; }
interface Props { stocks: StockItem[]; lastUpdated?: string; }

const defaultStocks: StockItem[] = [
  { symbol: 'AAPL', name: 'Apple Inc.', price: 178.72, change: 2.56, changePercent: 1.45 },
  { symbol: 'GOOGL', name: 'Alphabet Inc.', price: 141.80, change: -1.23, changePercent: -0.86 },
  { symbol: 'MSFT', name: 'Microsoft Corp.', price: 378.91, change: 4.12, changePercent: 1.10 },
  { symbol: 'AMZN', name: 'Amazon.com Inc.', price: 185.07, change: -0.95, changePercent: -0.51 },
  { symbol: 'TSLA', name: 'Tesla Inc.', price: 248.42, change: 7.83, changePercent: 3.25 },
  { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 875.28, change: 12.45, changePercent: 1.44 },
];

const GRID_STYLES = `
  .ggui-stock-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--ggui-spacing-6, 24px);
  }
  @media (max-width: 1024px) {
    .ggui-stock-grid { grid-template-columns: repeat(2, 1fr); }
  }
  @media (max-width: 768px) {
    .ggui-stock-grid { grid-template-columns: 1fr; }
  }
  @keyframes ggui-pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.4; }
  }
`;

function buildCardLabel(symbol: string | undefined, name: string | undefined): string {
  return (symbol ?? 'N/A') + ' - ' + (name ?? 'Unknown');
}

function buildChangeLabel(changeStr: string, direction: string, absPct: string): string {
  return 'Change: ' + changeStr + ', ' + direction + ' ' + absPct + ' percent';
}

export default function GeneratedComponent({
  stocks = defaultStocks,
  lastUpdated = new Date().toISOString(),
}: Props) {
  const [liveStocks, setLiveStocks] = useState(stocks);
  const [liveTimestamp, setLiveTimestamp] = useState<string>(lastUpdated);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'disconnected'>('connecting');
  const { motionEnabled } = useMotion();

  useEffect(() => {
    setLiveStocks(stocks);
    if (stocks.length > 0) setConnectionStatus('connected');
  }, [stocks]);

  useEffect(() => {
    setLiveTimestamp(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    let timeoutId: ReturnType<typeof setTimeout>;
    const resetTimeout = () => {
      clearTimeout(timeoutId);
      timeoutId = setTimeout(() => setConnectionStatus('disconnected'), 30000);
    };
    const handleAgentData = (event: Event) => {
      const detail = (event as CustomEvent).detail;
      if (detail?.stocks) {
        setLiveStocks(detail.stocks);
        setLiveTimestamp(detail.lastUpdated ?? new Date().toISOString());
        setConnectionStatus('connected');
        resetTimeout();
      }
    };
    const target = globalThis as unknown as EventTarget;
    target.addEventListener('ggui:agent-data', handleAgentData);
    resetTimeout();
    return () => {
      target.removeEventListener('ggui:agent-data', handleAgentData);
      clearTimeout(timeoutId);
    };
  }, []);

  const formatTimestamp = (iso: string): string => {
    try {
      return new Date(iso).toLocaleString(undefined, {
        month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit',
      });
    } catch { return iso; }
  };

  const statusColor =
    connectionStatus === 'connected' ? 'var(--ggui-color-success-500, #22c55e)'
      : connectionStatus === 'connecting' ? 'var(--ggui-color-warning-500, #f59e0b)'
        : 'var(--ggui-color-error-500, #ef4444)';

  const statusLabel =
    connectionStatus === 'connected' ? 'Live'
      : connectionStatus === 'connecting' ? 'Connecting...'
        : 'Disconnected';

  return (
    <>
      <MotionKeyframes />
      <style>{GRID_STYLES}</style>
      <Container maxWidth="xl">
        <div role="region" aria-label="Stock Market Dashboard">
          <Stack direction="vertical" gap={24}>

            {/* Header */}
            <Box background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-lg, 12px)" padding="var(--ggui-spacing-6, 24px)">
              <div role="banner" style={{ borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
                <Row align="center" gap={16} wrap>
                  <Text variant="h1" color="var(--ggui-color-primary-900, #0c4a6e)">Market Watch</Text>
                  <Spacer />
                  <Stack direction="vertical" align="end" gap={4}>
                    <div aria-live="polite" style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}>
                      <div style={{
                        width: 8, height: 8, flexShrink: 0,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        backgroundColor: statusColor,
                        animation: connectionStatus === 'connecting' ? 'ggui-pulse 1.5s ease-in-out infinite' : 'none',
                      }} />
                      <Text variant="caption" color={statusColor}>{statusLabel}</Text>
                    </div>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {'Last Updated: ' + formatTimestamp(liveTimestamp)}
                    </Text>
                  </Stack>
                </Row>
              </div>
            </Box>

            {/* Empty state */}
            {liveStocks.length === 0 ? (
              <Card padding={48} shadow="sm">
                <Stack direction="vertical" align="center" gap={16}>
                  <div style={{
                    width: 16, height: 16,
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    backgroundColor: statusColor,
                    animation: connectionStatus === 'connecting' ? 'ggui-pulse 1.5s ease-in-out infinite' : 'none',
                  }} />
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                    {connectionStatus === 'connecting' ? 'Connecting to market data...' : 'Disconnected. Waiting for data...'}
                  </Text>
                </Stack>
              </Card>
            ) : (
              <div className="ggui-stock-grid" role="list">
                {liveStocks.map((stock, index) => {
                  const changeVal = stock.change ?? 0;
                  const isPositive = changeVal >= 0;
                  const changeColor = isPositive ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
                  const borderColor = isPositive ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)';
                  const arrow = isPositive ? '▲' : '▼';
                  const sign = isPositive ? '+' : '';
                  const priceStr = '$' + (stock.price ?? 0).toFixed(2);
                  const changeStr = sign + changeVal.toFixed(2);
                  const pctStr = sign + (stock.changePercent ?? 0).toFixed(2) + '%';
                  const direction = isPositive ? 'up' : 'down';
                  const absPct = Math.abs(stock.changePercent ?? 0).toFixed(2);

                  return (
                    <div
                      key={stock.symbol ?? index}
                      role="listitem"
                      aria-label={buildCardLabel(stock.symbol, stock.name)}
                      style={{
                        animation: motionEnabled ? animation.fadeIn : 'none',
                        animationDelay: motionEnabled ? (index * 60) + 'ms' : '0ms',
                        animationFillMode: 'both',
                      }}
                    >
                      <Card shadow="sm" border>
                        <div style={{ borderLeft: '4px solid ' + borderColor, paddingLeft: 'var(--ggui-spacing-4, 16px)', transition: transition.colors }}>
                          <Stack direction="vertical" gap={12}>
                            <Row align="center" gap={8}>
                              <Text variant="h3" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{stock.symbol ?? 'N/A'}</Text>
                              <Spacer />
                              <Badge variant={isPositive ? 'success' : 'error'} size="sm" pill>{arrow}&nbsp;{pctStr}</Badge>
                            </Row>
                            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">{stock.name ?? 'Unknown'}</Text>
                            <Row align="end" gap={12}>
                              <span style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', color: 'var(--ggui-color-onSurface, #18181b)', lineHeight: 1.25 }}>{priceStr}</span>
                              <span
                                aria-label={buildChangeLabel(changeStr, direction, absPct)}
                                style={{ fontSize: 'var(--ggui-font-size-sm, 14px)', fontWeight: 'var(--ggui-font-weight-medium, 500)', color: changeColor, transition: transition.colors }}
                              >{changeStr}</span>
                            </Row>
                          </Stack>
                        </div>
                      </Card>
                    </div>
                  );
                })}
              </div>
            )}

          </Stack>
        </div>
      </Container>
    </>
  );
}

import { useState, useCallback } from 'react';
import {
  Container, Card, Box, Stack, Row, Text, Input, Select,
  Checkbox, RadioGroup, Button, Divider, Badge, Icon,
  MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string; email?: string; avatar?: string;
    role?: string; emailNotifications?: boolean; theme?: string;
  };
  onComplete?: (data: ProfileData) => void;
}

function AvatarPicker({ avatarOptions, avatar, setAvatar, showError }: {
  avatarOptions: string[]; avatar: string;
  setAvatar: (v: string) => void; showError: boolean;
}) {
  return (
    <Stack direction="vertical" gap={8}>
      <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
        Choose an Avatar{' '}
        <span aria-hidden="true" style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
      </Text>
      <div role="radiogroup" aria-label="Choose an avatar">
        <Row gap={12} wrap>
          {avatarOptions.map((emoji) => {
            const emojiLabel = 'Avatar ' + emoji;
            return (
              <div
                key={emoji}
                role="radio"
                aria-checked={avatar === emoji}
                aria-label={emojiLabel}
                tabIndex={0}
                onClick={() => setAvatar(emoji)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setAvatar(emoji); }
                }}
                onFocus={(e) => {
                  (e.currentTarget as HTMLDivElement).style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
                  (e.currentTarget as HTMLDivElement).style.outlineOffset = '2px';
                }}
                onBlur={(e) => {
                  (e.currentTarget as HTMLDivElement).style.outline = 'none';
                  (e.currentTarget as HTMLDivElement).style.outlineOffset = '0px';
                }}
                style={{
                  width: 64, height: 64,
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  border: avatar === emoji
                    ? '3px solid var(--ggui-color-primary-500, #0ea5e9)'
                    : '2px solid var(--ggui-color-outline, #d4d4d8)',
                  background: avatar === emoji
                    ? 'var(--ggui-color-primary-50, #f0f9ff)'
                    : 'var(--ggui-color-surface, #fafafa)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 32, cursor: 'pointer', transition: transition.colors,
                  boxShadow: avatar === emoji ? '0 0 0 3px var(--ggui-color-primary-100, #e0f2fe)' : 'none',
                  outline: 'none',
                }}
              >
                {emoji}
              </div>
            );
          })}
        </Row>
      </div>
      {showError && (
        <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">Please select an avatar</Text>
      )}
    </Stack>
  );
}

export default function GeneratedComponent({ initialProfile, avatarOptions, roleOptions, onComplete }: Props) {
  const { motionEnabled } = useMotion();
  const [currentStep, setCurrentStep] = useState(0);
  const [name, setName] = useState(initialProfile?.name ?? '');
  const [email, setEmail] = useState(initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar ?? '');
  const [role, setRole] = useState(initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme ?? 'light');
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [animKey, setAnimKey] = useState(0);

  const steps = ['Profile Setup', 'Preferences', 'Review & Confirm'];

  const validateName = (v: string) => !v.trim() ? 'Name is required' : '';
  const validateEmail = (v: string) => {
    if (!v.trim()) return 'Email is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v)) return 'Please enter a valid email address';
    return '';
  };

  const nameError = touched.name ? validateName(name) : '';
  const emailError = touched.email ? validateEmail(email) : '';
  const isStep1Valid = name.trim().length > 0 && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) && avatar.length > 0;
  const isStep2Valid = role.length > 0;
  const isCurrentStepValid = currentStep === 0 ? isStep1Valid : currentStep === 1 ? isStep2Valid : true;

  const handleNext = useCallback(() => {
    if (currentStep === 0) {
      setTouched(prev => ({ ...prev, name: true, email: true }));
      if (!isStep1Valid) return;
    }
    if (currentStep < steps.length - 1) { setCurrentStep(s => s + 1); setAnimKey(k => k + 1); }
  }, [currentStep, isStep1Valid, steps.length]);

  const handleBack = useCallback(() => {
    if (currentStep > 0) { setCurrentStep(s => s - 1); setAnimKey(k => k + 1); }
  }, [currentStep]);

  const handleComplete = useCallback(async () => {
    const profileData: ProfileData = { name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme };
    setIsSubmitting(true);
    try { if (onComplete) await onComplete(profileData); } finally { setIsSubmitting(false); }
  }, [name, email, avatar, role, emailNotifications, theme, onComplete]);

  const handleNameChange = (value: string) => {
    setName(value);
    if (!touched.name) setTouched(prev => ({ ...prev, name: true }));
  };
  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (!touched.email) setTouched(prev => ({ ...prev, email: true }));
  };

  const progressPercent = ((currentStep + 1) / steps.length) * 100;
  const roleSelectOptions = roleOptions.map(r => ({ value: r, label: r }));
  const stepLabel = steps[currentStep] ?? '';

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md" padding={24}>
        <Card padding={32} shadow="md">
          <Stack direction="vertical" gap={28}>
            <Stack direction="vertical" gap={4} align="center">
              <Text variant="h2" align="center" color="var(--ggui-color-onSurface, #18181b)">Welcome Aboard</Text>
              <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Let's set up your account in just a few steps.
              </Text>
            </Stack>

            {/* Step Indicator */}
            <Stack direction="vertical" gap={16}>
              <Row gap={0} align="center" justify="center">
                {steps.map((stepName, i) => (
                  <Row key={stepName} gap={0} align="center">
                    <div
                      role="listitem"
                      aria-current={i === currentStep ? 'step' : undefined}
                      style={{
                        width: 36, height: 36,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 'var(--ggui-font-size-sm, 14px)',
                        fontWeight: 'var(--ggui-font-weight-bold, 700)',
                        color: i <= currentStep ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                        background: i < currentStep ? 'var(--ggui-color-success-500, #22c55e)' : i === currentStep ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                        transition: transition.colors, flexShrink: 0,
                      }}
                    >
                      {i < currentStep ? '✓' : i + 1}
                    </div>
                    {i < steps.length - 1 && (
                      <div style={{
                        width: 64, height: 3, flexShrink: 0,
                        background: i < currentStep ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                        transition: transition.colors,
                      }} />
                    )}
                  </Row>
                ))}
              </Row>
              <Row gap={0} justify="between">
                {steps.map((stepName, i) => (
                  <Text key={stepName} variant="caption" align="center"
                    weight={i === currentStep ? 'semibold' : 'normal'}
                    color={i === currentStep ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                  >{stepName}</Text>
                ))}
              </Row>
              <div style={{ width: '100%', height: 4, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: 'var(--ggui-color-outlineVariant, #e4e4e7)', overflow: 'hidden' }}>
                <div
                  role="progressbar" aria-valuenow={currentStep + 1} aria-valuemin={1} aria-valuemax={steps.length} aria-label="Onboarding progress"
                  style={{
                    width: progressPercent + '%', height: '100%',
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    background: 'linear-gradient(90deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-600, #0284c7))',
                    transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)',
                  }}
                />
              </div>
            </Stack>

            <Divider margin={4} />

            <div key={animKey} style={{ animation: motionEnabled ? animation.fadeIn : 'none', minHeight: 280 }} role="region" aria-label={stepLabel}>

              {currentStep === 0 && (
                <Stack direction="vertical" gap={20}>
                  <Stack direction="vertical" gap={4}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Profile Setup</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Tell us about yourself to get started.</Text>
                  </Stack>
                  <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} required error={nameError} type="text" />
                  <Input label="Email Address" placeholder="you@example.com" value={email} onChange={handleEmailChange} required error={emailError} type="email" />
                  <AvatarPicker avatarOptions={avatarOptions} avatar={avatar} setAvatar={setAvatar} showError={!avatar && touched.name === true} />
                </Stack>
              )}

              {currentStep === 1 && (
                <Stack direction="vertical" gap={20}>
                  <Stack direction="vertical" gap={4}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Preferences</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Customize your experience.</Text>
                  </Stack>
                  <Select label="Role" value={role} onChange={setRole} options={roleSelectOptions} placeholder="Select your role" required />
                  <Checkbox label="Email Notifications" checked={emailNotifications} onChange={setEmailNotifications} description="Receive email notifications about updates and activity" />
                  <Stack direction="vertical" gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Theme Preference</Text>
                    <RadioGroup value={theme} onChange={setTheme} direction="horizontal" options={[
                      { value: 'light', label: 'Light', description: 'Clean and bright appearance' },
                      { value: 'dark', label: 'Dark', description: 'Easy on the eyes in low light' },
                    ]} />
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack direction="vertical" gap={20}>
                  <Stack direction="vertical" gap={4}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Review & Confirm</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please review your information before completing setup.</Text>
                  </Stack>
                  <Box padding={20} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
                    <Stack direction="vertical" gap={16}>
                      <Badge variant="primary" size="sm">Profile</Badge>
                      <Row gap={16} align="center">
                        <div aria-label="Selected avatar" style={{
                          width: 56, height: 56, borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          background: 'var(--ggui-color-surface, #fafafa)',
                          border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          fontSize: 28, flexShrink: 0,
                        }}>{avatar}</div>
                        <Stack direction="vertical" gap={2}>
                          <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{name}</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{email}</Text>
                        </Stack>
                      </Row>
                    </Stack>
                  </Box>
                  <Box padding={20} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
                    <Stack direction="vertical" gap={16}>
                      <Badge variant="secondary" size="sm">Preferences</Badge>
                      <Stack direction="vertical" gap={12}>
                        <Row gap={8} align="center">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role:</Text>
                          <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">{role}</Text>
                        </Row>
                        <Row gap={8} align="center">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications:</Text>
                          <Badge variant={emailNotifications ? 'success' : 'default'} size="sm">{emailNotifications ? 'On' : 'Off'}</Badge>
                        </Row>
                        <Row gap={8} align="center">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme:</Text>
                          <Badge variant="info" size="sm">{theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Badge>
                        </Row>
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>
              )}

            </div>

            <Divider margin={4} />

            <Row justify="between" align="center">
              {currentStep > 0 ? (
                <Button variant="outline" onClick={handleBack} leftIcon={<Icon name="chevron-left" size={16} />}>
                  {currentStep === 2 ? 'Go Back' : 'Back'}
                </Button>
              ) : (<div />)}
              {currentStep < steps.length - 1 ? (
                <Button variant="primary" onClick={handleNext} disabled={!isCurrentStepValid} rightIcon={<Icon name="chevron-right" size={16} />}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleComplete} loading={isSubmitting} disabled={isSubmitting} leftIcon={<Icon name="check" size={16} />}>
                  {isSubmitting ? 'Completing...' : 'Complete Setup'}
                </Button>
              )}
            </Row>

          </Stack>
        </Card>
      </Container>
    </>
  );
}

import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Divider,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * A clean, responsive weather dashboard card designed with GGUI primitives.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°',
  forecast = [],
}: Props) {
  const { motionEnabled } = useMotion();

  /**
   * Returns a fallback emoji based on condition text if specific icons aren't provided.
   */
  const getWeatherEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  const today = new Date().toLocaleDateString('en-US', { 
    weekday: 'long', 
    month: 'long', 
    day: 'numeric' 
  });

  return (
    <Card 
      padding={24} 
      shadow="md"
      style={{
        background: 'var(--ggui-color-surface, #ffffff)',
        maxWidth: '450px',
        width: '100%',
        animation: motionEnabled ? animation.fadeIn : 'none',
        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
      }}
    >
      <MotionKeyframes />

      <Stack gap={24}>
        {/* City & Date Header */}
        <Stack gap={4}>
          <Text variant="h2" weight="bold">
            {city}
          </Text>
          <Text color="var(--ggui-color-onSurfaceVariant, #52525b)" variant="caption">
            {today}
          </Text>
        </Stack>

        {/* Current Conditions Main Display */}
        <Row align="center" justify="between">
          <Stack gap={0}>
            <Text 
              style={{ 
                lineHeight: 1, 
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-onSurface, #18181b)',
                fontSize: '4.5rem'
              }}
            >
              {Math.round(temperature)}{unit}
            </Text>
            <Text 
              variant="h3" 
              weight="medium" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>
          <Text style={{ fontSize: '4rem' }}>
            {getWeatherEmoji(condition)}
          </Text>
        </Row>

        {/* Secondary Stats Row */}
        <Row gap={24} style={{ 
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', 
          padding: 'var(--ggui-spacing-4, 16px)', 
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)' 
        }}>
          <Stack gap={4} align="center" style={{ flex: 1 }}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="bold">
              HUMIDITY
            </Text>
            <Text weight="semibold">
              {humidity}%
            </Text>
          </Stack>

          <Divider orientation="vertical" />

          <Stack gap={4} align="center" style={{ flex: 1 }}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="bold">
              WIND
            </Text>
            <Text weight="semibold">
              {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
            </Text>
          </Stack>
        </Row>

        <Divider margin={8} />

        {/* 5-Day Forecast Strip */}
        <Row justify="between" gap={8}>
          {forecast.slice(0, 5).map((item, index) => {
            const dayKey = (item.day || 'day') + '-' + index;
            return (
              <Stack 
                key={dayKey} 
                align="center" 
                gap={8} 
                style={{ 
                  flex: 1,
                  padding: 'var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                }}
              >
                <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ? item.day.toUpperCase() : '---'}
                </Text>

                <Text style={{ fontSize: '1.75rem' }}>
                  {item.icon || getWeatherEmoji(condition)}
                </Text>

                <Stack gap={0} align="center">
                  <Text variant="bodySmall" weight="bold">
                    {Math.round(item.high ?? 0)}{unit}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {Math.round(item.low ?? 0)}{unit}
                  </Text>
                </Stack>
              </Stack>
            );
          })}
        </Row>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Button,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: submit survey callback */
  onSubmit: (data: any) => void;
}

export default function SurveyForm({
  featureOptions = ['UI Design', 'Performance', 'Documentation'],
  satisfactionLabels = ['Poor', 'Fair', 'Good', 'Very Good', 'Excellent'],
  onSubmit
}: Props) {
  const [step, setStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const toggleFeature = (f: string, checked: boolean) => {
    if (checked) setFeatures([...features, f]);
    else setFeatures(features.filter(item => item !== f));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await onSubmit({ name, email, satisfaction, features, comments });
    } finally {
      setIsSubmitting(false);
    }
  };

  const isEmailValid = email.includes('@');
  const canGoNext = step === 0 ? (name.trim() !== '' && isEmailValid) : step === 1 ? satisfaction !== '' : true;

  const progressValue = ((step + 1) / 5) * 100;

  return (
    <Container maxWidth="md">
      <Card padding={24}>
        <Stack gap={24} role="form" aria-label="Survey">
          <Stack gap={8}>
            <Text variant="h2" align="center">Feedback Survey</Text>
            <Text variant="caption" align="center">Step {step + 1} of 5</Text>
            <Box background="var(--ggui-color-outlineVariant)" borderRadius="99px" style={{ height: 4, overflow: 'hidden' }}>
              <Box 
                background="var(--ggui-color-primary-600)" 
                style={{ height: '100%', width: progressValue + '%', transition: 'width 0.2s' }} 
              />
            </Box>
          </Stack>

          <Box style={{ minHeight: 320 }}>
            {step === 0 && (
              <Stack gap={16}>
                <Input label="Name" value={name} onChange={setName} />
                <Input label="Email" value={email} onChange={setEmail} />
              </Stack>
            )}

            {step === 1 && (
              <RadioGroup
                label="Overall Satisfaction"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionLabels.map((l, i) => ({ value: (i+1).toString(), label: l }))}
              />
            )}

            {step === 2 && (
              <Stack gap={12}>
                <Text variant="label">Feature Interests</Text>
                <Stack gap={8}>
                  {featureOptions.map(f => (
                    <Checkbox key={f} label={f} checked={features.includes(f)} onChange={(c) => toggleFeature(f, c)} />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <TextArea label="Comments" value={comments} onChange={setComments} />
            )}

            {step === 4 && (
              <Stack gap={12}>
                <Text variant="h3">Review Summary</Text>
                <Divider />
                <Text variant="bodySmall">Name: {name}</Text>
                <Text variant="bodySmall">Email: {email}</Text>
                <Text variant="bodySmall">Satisfaction: {satisfactionLabels[parseInt(satisfaction)-1] || 'None'}</Text>
                <Text variant="bodySmall">Features: {features.join(', ') || 'None'}</Text>
                <Text variant="bodySmall">Comments: {comments || 'None'}</Text>
              </Stack>
            )}
          </Box>

          <Divider />

          <Row justify="between">
            <Button variant="outline" onClick={() => setStep(step - 1)} disabled={step === 0 || isSubmitting}>Back</Button>
            {step < 4 ? (
              <Button variant="primary" onClick={() => setStep(step + 1)} disabled={!canGoNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting}>Submit</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState } from 'react';
import {
