const CATEGORY_MAP: Record<string, { label: string; backgroundColor: string; textColor: string }> = {
  'alkali-metal': { label: 'Alkali Metal', backgroundColor: 'var(--ggui-color-primary-100)', textColor: 'var(--ggui-color-primary-900)' },
  'alkaline-earth': { label: 'Alkaline Earth', backgroundColor: 'var(--ggui-color-primary-200)', textColor: 'var(--ggui-color-primary-900)' },
  'transition-metal': { label: 'Transition Metal', backgroundColor: 'var(--ggui-color-primary-300)', textColor: 'var(--ggui-color-primary-900)' },
  'post-transition-metal': { label: 'Post-Transition Metal', backgroundColor: 'var(--ggui-color-success-100)', textColor: 'var(--ggui-color-onSurface)' },
  'metalloid': { label: 'Metalloid', backgroundColor: 'var(--ggui-color-warning-100)', textColor: 'var(--ggui-color-onSurface)' },
  'nonmetal': { label: 'Nonmetal', backgroundColor: 'var(--ggui-color-error-100)', textColor: 'var(--ggui-color-onSurface)' },
  'halogen': { label: 'Halogen', backgroundColor: 'var(--ggui-color-info-100)', textColor: 'var(--ggui-color-onSurface)' },
