  'lanthanide': { label: 'Lanthanide', backgroundColor: 'var(--ggui-color-container)', textColor: 'var(--ggui-color-onContainer)' },
  'actinide': { label: 'Actinide', backgroundColor: 'var(--ggui-color-error-200)', textColor: 'var(--ggui-color-onSurface)' },
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);
  const { motionEnabled } = useMotion();

  const isElementVisible = (el: Props['elements'][number]) => {
    if (!searchTerm) return true;
    const s = searchTerm.toLowerCase();
    const nameMatch = el.name ? el.name.toLowerCase().includes(s) : false;
    const symbolMatch = el.symbol ? el.symbol.toLowerCase().includes(s) : false;
    return nameMatch || symbolMatch;
  };

  const categories = Object.keys(CATEGORY_MAP);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Row justify="between" align="end" wrap>
          <Stack gap={4}>
            <Text variant="h1" weight="bold">Periodic Table</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Interactive chemistry guide</Text>
          </Stack>
          <Input label="Search Elements" placeholder="Name or symbol..." value={searchTerm} onChange={setSearchTerm} leftIcon={<Icon name="search" size={16} />} />
        </Row>

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap={12}>
            <Text variant="label" weight="semibold">Categories</Text>
            <Row gap={12} wrap>
              {categories.map((catKey) => {
                const cat = CATEGORY_MAP[catKey];
                return (
                  <Row key={catKey} gap={4} align="center">
                    <div style={{ width: 14, height: 14, borderRadius: 4, backgroundColor: cat.backgroundColor, border: '1px solid var(--ggui-color-outlineVariant)' }} />
                    <Text variant="caption">{cat.label}</Text>
                  </Row>
                );
              })}
            </Row>
          </Stack>
        </Card>

        <Box style={{ overflowX: 'auto', paddingBottom: 16 }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 4, minWidth: 1000 }}>
            {elements.map((el) => {
              const cat = el.category ? CATEGORY_MAP[el.category] : null;
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const isVisible = isElementVisible(el);
              const cellBg = cat ? cat.backgroundColor : 'var(--ggui-color-surfaceVariant)';
              const cellText = cat ? cat.textColor : 'inherit';

              return (
                <div
                  key={el.atomicNumber ? el.atomicNumber.toString() : (el.symbol || 'unknown')}
                  onClick={() => setSelectedElement(el)}
                  style={{
                    gridColumn: el.col,
                    gridRow: el.row,
                    backgroundColor: cellBg,
                    color: cellText,
                    borderRadius: 4,
                    border: isSelected ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outlineVariant)',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    height: 60,
                    opacity: isVisible ? 1 : 0.1,
                    transition: transition.normal,
                    transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                    position: 'relative'
                  }}
                >
                  <span style={{ position: 'absolute', top: 2, left: 4, fontSize: 9, fontWeight: 'bold' }}>{el.atomicNumber}</span>
                  <Text weight="bold" variant="body">{el.symbol}</Text>
                  <span style={{ fontSize: 8, whiteSpace: 'nowrap', overflow: 'hidden', width: '90%', textAlign: 'center' }}>{el.name}</span>
                </div>
              );
            })}
          </div>
        </Box>

        {selectedElement && (
          <Card padding={24} style={{ animation: motionEnabled ? animation.slideInUp : 'none', borderLeft: '8px solid var(--ggui-color-outline)' }}>
            <Stack gap={24}>
              <Row justify="between">
                <Stack gap={4}>
                  <Row gap={8} align="center">
                    <Text variant="h2" weight="bold">{selectedElement.name}</Text>
                    <Badge variant="primary">{selectedElement.symbol}</Badge>
                  </Row>
                  <Text variant="caption">{selectedElement.category ? CATEGORY_MAP[selectedElement.category]?.label : 'Element'}</Text>
                </Stack>
                <Text variant="h1" weight="bold" color="var(--ggui-color-primary-600)">{selectedElement.atomicNumber}</Text>
              </Row>
              <Divider />
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 24 }}>
                <Stack gap={4}>
                  <Text variant="label">Atomic Weight</Text>
                  <Text weight="semibold">{selectedElement.atomicWeight} u</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Configuration</Text>
                  <Text weight="semibold" style={{ fontFamily: 'monospace' }}>{selectedElement.electronConfiguration}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Table Position</Text>
                  <Text>Row {selectedElement.row}, Column {selectedElement.col}</Text>
                </Stack>
              </div>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Input, 
  Button, 
  Badge, 
  Box, 
  Divider, 
  Icon, 
  MotionKeyframes 
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface({
  title = "Chat",
  currentUser = "User",
  participantCount,
  messages = [],
  onSendMessage
}: Props) {
  const [inputText, setInputText] = useState('');
  const [localMessages, setLocalMessages] = useState<Message[]>(messages);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setLocalMessages(messages); }, [messages]);

  useEffect(() => {
    const handler = (e: any) => { if (e && e.detail) setLocalMessages(prev => [...prev, e.detail]); };
    const win = typeof globalThis !== 'undefined' ? globalThis : null;
    if (win && (win as any).addEventListener) {
      (win as any).addEventListener('ggui:agent-data', handler);
      return () => (win as any).removeEventListener('ggui:agent-data', handler);
    }
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [localMessages]);

  const doSend = () => {
    if (!inputText.trim()) return;
    const ts = new Date().toISOString();
    const m = { sender: currentUser, text: inputText.trim(), timestamp: ts };
    setLocalMessages(prev => [...prev, m]);
    if (onSendMessage) onSendMessage({ text: m.text, timestamp: ts });
    setInputText('');
  };

  const fmt = (s?: string) => {
    if (!s) return '';
    try { return new Date(s).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }
    catch { return ''; }
  };

  return (
    <Container maxWidth="md" padding={0}>
      <MotionKeyframes />
      <Card padding={0} style={{ height: '600px', display: 'flex', flexDirection: 'column', overflow: 'hidden', backgroundColor: 'var(--ggui-color-surface, #fafafa)', border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Box padding="16px" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap={12} align="center">
              <Text variant="h3" weight="bold">{title}</Text>
              {participantCount !== undefined && <Badge variant="info" pill size="sm">{participantCount + ' online'}</Badge>}
            </Stack>
            <Icon name="settings" size={20} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
          </Row>
        </Box>
        <Divider margin={0} />
        <Box ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: '16px', backgroundColor: 'var(--ggui-color-surface, #fafafa)' }} role="log">
          <Stack gap={12}>
            {localMessages.map((m, i) => {
              const isMe = m.sender === currentUser;
              const isC = i > 0 && localMessages[i - 1].sender === m.sender;
              return (
                <Stack key={(m.timestamp || 'm') + i} align={isMe ? 'end' : 'start'} gap={4} style={{ animation: animation.fadeIn, maxWidth: '85%', alignSelf: isMe ? 'flex-end' : 'flex-start' }}>
                  {!isMe && !isC && <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{m.sender}</Text>}
                  <Box padding="8px 12px" borderRadius="12px" style={{ backgroundColor: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: isMe ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)', borderBottomRightRadius: isMe && !isC ? 0 : 12, borderBottomLeftRadius: !isMe && !isC ? 0 : 12 }}>
                    <Text variant="body" color="inherit">{m.text}</Text>
                  </Box>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{fmt(m.timestamp)}</Text>
                </Stack>
              );
            })}
          </Stack>
        </Box>
        <Divider margin={0} />
        <Box padding="16px" background="var(--ggui-color-surface, #fafafa)">
          <Stack gap={4}>
            <Text variant="label">Message</Text>
            <Row gap={12} align="center">
              <Input label="Message" placeholder="Type here..." value={inputText} onChange={setInputText} />
              <Button variant="primary" onClick={doSend} disabled={!inputText.trim()}>Send</Button>
            </Row>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Badge,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

type StockItem = {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
};

interface Props {
  stocks: Array<StockItem>;
  lastUpdated?: string;
}

export default function StockTickerDashboard({ stocks, lastUpdated }: Props) {
  const [data, setData] = useState(stocks || []);
  const [updated, setUpdated] = useState(lastUpdated);
  const [live, setLive] = useState(false);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    const onData = (e: any) => {
      if (e.detail) {
        if (e.detail.stocks) setData(e.detail.stocks);
        if (e.detail.lastUpdated) setUpdated(e.detail.lastUpdated);
        setLive(true);
      }
    };
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', onData);
    }
    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', onData);
      }
    };
  }, []);

  const fmtCurrency = (n?: number) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(n ?? 0);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Row align="center" justify="between" wrap>
          <Stack gap={4}>
            <Text variant="h1" weight="bold">Market Watch</Text>
            <Row gap={12} align="center">
              <Badge variant={live ? 'success' : 'warning'} pill>
                {live ? 'Live' : 'Connecting'}
              </Badge>
              <Text variant="caption">Updated: {updated ? new Date(updated).toLocaleTimeString() : '...'}</Text>
            </Row>
          </Stack>
        </Row>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
          gap: 'var(--ggui-spacing-6, 24px)',
        }}>
          {data.map((s, i) => {
            const up = (s.change ?? 0) >= 0;
            const c = up ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
            return (
              <Card key={s.symbol || i} padding={24} style={{ 
                border: up ? '1px solid var(--ggui-color-success-500)' : '1px solid var(--ggui-color-error-500)',
                animation: motionEnabled ? animation.slideInUp : 'none',
                animationDelay: (i * 0.05) + 's'
              }}>
                <Stack gap={20}>
                  <Row justify="between">
                    <Stack gap={2}>
                      <Text variant="h2" weight="bold">{s.symbol}</Text>
                      <Text variant="caption">{s.name}</Text>
                    </Stack>
                    <Icon name={up ? 'chevron-up' : 'chevron-down'} color={c} size={20} />
                  </Row>
                  <Stack gap={4}>
                    <Text variant="h1" weight="bold">{fmtCurrency(s.price)}</Text>
                    <Row gap={8} align="center">
                      <Text weight="semibold" style={{ color: c }}>{up ? '▲' : '▼'} {Math.abs(s.changePercent ?? 0).toFixed(2)}%</Text>
                      <Text variant="caption">({up ? '+' : ''}{s.change?.toFixed(2)})</Text>
                    </Row>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

