/** Helper to provide a fallback emoji based on common conditions */
function getWeatherEmoji(condition: string): string {
  const c = condition.toLowerCase();
  if (c.indexOf('sun') !== -1 || c.indexOf('clear') !== -1) return '☀️';
  if (c.indexOf('cloud') !== -1) return '☁️';
  if (c.indexOf('rain') !== -1 || c.indexOf('shower') !== -1) return '🌧️';
  if (c.indexOf('snow') !== -1) return '❄️';
  if (c.indexOf('thunder') !== -1) return '⛈️';
  if (c.indexOf('mist') !== -1 || c.indexOf('fog') !== -1) return '🌫️';
  return '⛅';
}

