  satisfactionLabels: string[];
  /** Callback for submission */
  onSubmit?: (data: any) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

/**
 * A comprehensive multi-step survey component.
 * Steps: 1. Identity, 2. Satisfaction, 3. Interests, 4. Comments, 5. Review.
 */
export default function SurveyForm({ featureOptions = [], satisfactionLabels = [], onSubmit }: Props) {
  const [step, setStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { motionEnabled } = useMotion();

  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: ''
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const handleNext = () => {
    if (step === 0) {
      const e: Record<string, string> = {};
      if (!formData.name.trim()) e.name = 'Name is required';
      if (!formData.email.trim()) e.email = 'Email is required';
      else if (!validateEmail(formData.email)) e.email = 'Invalid email address';

      if (Object.keys(e).length > 0) {
        setErrors(e);
        return;
      }
    }
    setErrors({});
    setStep(s => Math.min(s + 1, 4));
  };

  const handleBack = () => setStep(s => Math.max(s - 1, 0));

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) {
        await onSubmit(formData);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const currentStepNum = step + 1;
  const progressPercent = (currentStepNum / 5) * 100;
  const progressWidth = progressPercent + '%';

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Card padding={24} shadow="md">
        <Stack gap={24} role="form" aria-label="Customer Survey Form">
          <Stack gap={8}>
            <Row justify="between">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Step {currentStepNum} of 5
              </Text>
              <Text variant="caption" weight="bold" color="var(--ggui-color-primary-600)">
                {Math.round(progressPercent)}%
              </Text>
            </Row>
            <div style={{ height: 4, background: 'var(--ggui-color-outlineVariant)', borderRadius: 2, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: progressWidth, background: 'var(--ggui-color-primary-600)', transition: 'width 0.3s' }} />
            </div>
          </Stack>

          <Box style={{ minHeight: 320, animation: motionEnabled ? animation.fadeIn : 'none' }}>
            {step === 0 && (
              <Stack gap={16}>
                <Text variant="h3">Basic Information</Text>
                <Input label="Full Name" value={formData.name} onChange={v => setFormData(d => ({ ...d, name: v }))} error={errors.name} required />
                <Input label="Email Address" type="email" value={formData.email} onChange={v => setFormData(d => ({ ...d, email: v }))} error={errors.email} required />
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={16}>
                <Text variant="h3">Experience Rating</Text>
                <RadioGroup 
                  label="How satisfied are you with our service?" 
                  value={formData.satisfaction} 
                  onChange={v => setFormData(d => ({ ...d, satisfaction: v }))} 
                  options={satisfactionLabels.map((l, i) => ({ label: (i + 1) + ' - ' + l, value: String(i + 1) }))} 
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="h3">Feature Interests</Text>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Select the features you use most often:</Text>
                <Stack gap={12}>
                  {featureOptions.map(f => (
                    <Checkbox 
                      key={f} 
                      label={f} 
                      checked={formData.features.includes(f)} 
                      onChange={c => setFormData(d => ({ ...d, features: c ? [...d.features, f] : d.features.filter(x => x !== f) }))} 
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={16}>
                <Text variant="h3">Any Feedback?</Text>
                <TextArea label="Your Comments" placeholder="Tell us more..." value={formData.comments} onChange={v => setFormData(d => ({ ...d, comments: v }))} maxLength={500} rows={6} />
                <Row justify="end">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{formData.comments.length} / 500 characters</Text>
                </Row>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={16}>
                <Text variant="h3">Summary & Review</Text>
                <Card border padding={16} background="var(--ggui-color-surfaceVariant)">
                  <Stack gap={12}>
                    <Row justify="between"><Text weight="semibold">Name:</Text><Text>{formData.name}</Text></Row>
                    <Row justify="between"><Text weight="semibold">Email:</Text><Text>{formData.email}</Text></Row>
                    <Row justify="between"><Text weight="semibold">Rating:</Text><Text>{formData.satisfaction ? formData.satisfaction + '/5' : 'None'}</Text></Row>
                    <Divider />
                    <Stack gap={4}><Text weight="semibold">Interests:</Text><Text>{formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}</Text></Stack>
                    <Divider />
                    <Stack gap={4}><Text weight="semibold">Comments:</Text><Text style={{ whiteSpace: 'pre-wrap' }}>{formData.comments || 'No comments provided'}</Text></Stack>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider />

          <Row justify="between" gap={16}>
            <Button variant="ghost" disabled={step === 0 || isSubmitting} onClick={handleBack} leftIcon={<Icon name="chevron-left" size={18} />}>
              Back
            </Button>
            {step === 4 ? (
              <Button variant="primary" loading={isSubmitting} onClick={handleSubmit} rightIcon={<Icon name="check" size={18} />}>
                Submit Survey
              </Button>
            ) : (
              <Button variant="primary" disabled={step === 0 && (!formData.name || !validateEmail(formData.email))} onClick={handleNext} rightIcon={<Icon name="chevron-right" size={18} />}>
                Next
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

