export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<any>(null);
  const { motionEnabled } = useMotion();

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return elements.filter(e => 
      (e.name || '').toLowerCase().includes(q) || 
      (e.symbol || '').toLowerCase().includes(q)
    );
  }, [elements, searchQuery]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Stack gap={16}>
          <Text variant="h1">Periodic Table</Text>
          <Box style={{ width: '100%', maxWidth: '320px' }}>
            <Input label="Search" placeholder="Filter..." value={searchQuery} onChange={(v) => setSearchQuery(v)} />
          </Box>

          <Card padding={12} border shadow="none" style={{ background: 'var(--ggui-color-surfaceVariant)' }}>
            <Row gap={12} wrap justify="center">
              {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
                <Row key={cat} gap={8} align="center">
                  <div style={{ width: 12, height: 12, borderRadius: 'var(--ggui-shape-radius-sm)', backgroundColor: color, border: '1px solid var(--ggui-color-outline)' }} />
                  <Text variant="caption">{cat.replace('-', ' ')}</Text>
                </Row>
              ))}
            </Row>
          </Card>
        </Stack>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-6, 24px)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(64px, 1fr))', gap: 'var(--ggui-spacing-1, 4px)', minWidth: '1024px' }}>
            {elements.map((el, i) => (
              <button
                key={i}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  backgroundColor: CATEGORY_COLORS[el.category || ''] || 'var(--ggui-color-surface)',
                  border: selectedElement === el ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  padding: 'var(--ggui-spacing-1)',
                  opacity: searchQuery && !filteredElements.includes(el) ? 0.3 : 1,
                  cursor: 'pointer',
                  minHeight: 'var(--ggui-spacing-16, 64px)',
                  position: 'relative',
                  transition: transition.normal,
                }}
              >
                <Text style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)', fontSize: 'var(--ggui-font-size-xs)' }}>{el.atomicNumber}</Text>
                <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-xl)' }}>{el.symbol}</Text>
              </button>
            ))}
          </div>
        </Box>

        {selectedElement && (
          <Card 
            padding={24} 
            style={{ 
              animation: motionEnabled ? animation.slideInUp : 'none',
              borderLeftWidth: '6px',
              borderLeftStyle: 'solid',
              borderLeftColor: CATEGORY_COLORS[selectedElement.category || ''] || 'var(--ggui-color-outline)'
            }}
          >
            <Stack gap={20}>
              <Row justify="between" align="start">
                <Stack gap={4}>
                  <Text variant="h2">{selectedElement.name} ({selectedElement.symbol})</Text>
                  <Badge variant="secondary">{selectedElement.category}</Badge>
                </Stack>
                <Text variant="h1" weight="bold">{selectedElement.atomicNumber}</Text>
              </Row>
              <Divider />
              <Row wrap gap={32}>
                <Stack gap={4}><Text variant="label">Weight</Text><Text>{selectedElement.atomicWeight}</Text></Stack>
                <Stack gap={4}><Text variant="label">Configuration</Text><Text style={{ fontFamily: 'monospace' }}>{selectedElement.electronConfiguration}</Text></Stack>
              </Row>
