import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  Box,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Title of the chat window */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Online participant count */
  participantCount?: number;
  /** Initial messages list */
  messages: Message[];
  /** Callback to send message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * Chat component with Converse interaction style.
 */
export default function GeneratedComponent({
  title = 'Discussion',
  currentUser = 'You',
  participantCount = 0,
  messages = [],
  onSendMessage
}: Props) {
  const [inputText, setInputText] = useState('');
  const [list, setList] = useState<Message[]>(messages);
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => { setList(messages); }, [messages]);

  useEffect(() => {
    const handleStream = (e: any) => {
      const { detail } = e;
      if (detail && (detail.text || detail.message)) {
        setList(prev => [...prev, {
          sender: detail.sender || 'Assistant',
          text: detail.text || detail.message,
          timestamp: detail.timestamp || new Date().toISOString()
        }]);
      }
    };
    addEventListener('ggui:agent-data', handleStream as EventListener);
    return () => removeEventListener('ggui:agent-data', handleStream as EventListener);
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [list]);

  const handleSend = () => {
    const text = inputText.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    const payload = { text, timestamp };
    setList(prev => [...prev, { sender: currentUser, ...payload }]);
    if (onSendMessage) onSendMessage(payload);
    setInputText('');
  };

  return (
    <Card padding={0} border shadow="sm" style={{ height: '600px', display: 'flex', flexDirection: 'column', background: 'var(--ggui-color-surface)' }}>
      <MotionKeyframes />
      <Box padding="16px" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Row justify="between" align="center">
          <Text variant="h3" weight="bold">{title}</Text>
          <Badge variant="success" size="sm" pill>{participantCount} Online</Badge>
        </Row>
      </Box>
      <Box ref={scrollRef} padding="16px" style={{ flex: 1, overflowY: 'auto', background: 'var(--ggui-color-surfaceVariant)' }}>
        <Stack gap={12}>
          {list.map((m, i) => (
            <Stack key={i} align={m.sender === currentUser ? 'end' : 'start'} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
              <Text variant="label" weight="semibold">{m.sender}</Text>
              <Box padding="8px 16px" style={{ background: m.sender === currentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surface)', color: m.sender === currentUser ? '#fff' : 'var(--ggui-color-onSurface)', borderRadius: '12px' }}>
                <Text style={{ color: 'inherit' }}>{m.text}</Text>
              </Box>
            </Stack>
          ))}
        </Stack>
      </Box>
      <Box padding="16px" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack gap={8}>
          <Text as="label" htmlFor="msg-input" variant="label">Message</Text>
          <Row gap={12} align="center">
            <Input id="msg-input" label="Message" placeholder="Type here..." value={inputText} onChange={setInputText} />
            <Button variant="primary" onClick={handleSend} disabled={!inputText.trim()}>Send</Button>
          </Row>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Row, 
  Card, 
  Text, 
  Heading, 
  Spacer, 
  MotionKeyframes, 
  useMotion 
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: StockData[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard Component
 * Renders a real-time dashboard for monitoring stock prices.
 */
export default function StockTickerDashboard({ 
  stocks: initialStocks = [], 
  lastUpdated: initialLastUpdated 
}: Props) {
  const [stocks, setStocks] = useState<StockData[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const { motionEnabled } = useMotion();

  // Interaction: Broadcast (Stream Contract)
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
      }
    };

    addEventListener('ggui:agent-data', handleAgentData);
    return () => removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatPrice = (val?: number) => {
    if (typeof val !== 'number') return '0.00';
    return val.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  const formatTime = (iso?: string) => {
    if (!iso) return 'Updating...';
    try {
      return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch (e) {
      return 'Syncing';
    }
  };

  const gridStyle: React.CSSProperties = {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: 'var(--ggui-spacing-4, 16px)',
    width: '100%'
  };

  const pulseStyle: React.CSSProperties = {
    width: 'var(--ggui-spacing-2, 8px)', 
    height: 'var(--ggui-spacing-2, 8px)', 
    borderRadius: 'var(--ggui-shape-radius-full, 9999px)', 
    backgroundColor: 'var(--ggui-color-success-500, #22c55e)',
    boxShadow: '0 0 var(--ggui-spacing-2, 8px) var(--ggui-color-success-500, #22c55e)'
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />

      <Stack gap={24}>
        {/* Header Section */}
        <Row align="center" justify="between" wrap>
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Real-time market insights and indices
            </Text>
          </Stack>

          <Row align="center" gap={8}>
            <div style={pulseStyle} aria-hidden="true" />
            <Text variant="label">
              Last Updated: {formatTime(lastUpdated)}
            </Text>
          </Row>
        </Row>

        {/* Responsive Stock Grid */}
        <div style={gridStyle}>
          {stocks.length === 0 ? (
            <Card padding="var(--ggui-spacing-12, 48px)" border>
              <Stack align="center" justify="center" gap={12}>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Connecting to live market feed...
                </Text>
              </Stack>
            </Card>
          ) : (
            stocks.map((stock, index) => {
              const changeVal = stock.change ?? 0;
              const isPositive = changeVal >= 0;
              const statusColor = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';
              const statusBg = isPositive 
                ? 'var(--ggui-color-success-50, #f0fdf4)' 
                : 'var(--ggui-color-error-50, #fef2f2)';

              const cardStyle: React.CSSProperties = {
                borderColor: statusColor,
                borderWidth: '1px',
                borderStyle: 'solid',
                transition: transition.colors,
                animation: motionEnabled ? animation.fadeIn : 'none',
                animationDelay: (index * 50) + 'ms',
                backgroundColor: 'var(--ggui-color-surface, #fafafa)'
              };

              const arrowStyle: React.CSSProperties = {
                color: statusColor,
                fontSize: 'var(--ggui-font-size-xl, 20px)'
              };

              const changeBadgeStyle: React.CSSProperties = {
                backgroundColor: statusBg,
                padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                border: '1px solid ' + statusColor + '33'
              };

              return (
                <Card 
                  key={stock.symbol || ('stock-' + index)}
                  padding="var(--ggui-spacing-4, 16px)"
                  style={cardStyle}
                >
                  <Stack gap={12}>
                    <Row justify="between" align="start">
                      <Stack gap={0}>
                        <Text weight="bold" variant="h3">{stock.symbol}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {stock.name}
                        </Text>
                      </Stack>
                      <Text style={arrowStyle}>
                        {isPositive ? '▲' : '▼'}
                      </Text>
                    </Row>

                    <Spacer size={8} />

                    <Stack gap={4}>
                      <Text variant="h2" weight="bold">
                        {'$' + formatPrice(stock.price)}
                      </Text>
                      <Row gap={8} align="center">
                        <Text 
                          weight="medium" 
                          style={{ color: statusColor }}
                        >
                          {(isPositive ? '+' : '') + changeVal.toFixed(2)}
                        </Text>
                        <div style={changeBadgeStyle}>
                          <Text 
                            variant="caption" 
                            weight="bold" 
                            style={{ color: statusColor }}
                          >
                            {(isPositive ? '+' : '') + (stock.changePercent?.toFixed(2) || '0.00') + '%'}
                          </Text>
                        </div>
                      </Row>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          )}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, Select, Checkbox, RadioGroup, Button, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  complete: (data: any) => void;
}

export default function OnboardingWizard(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, complete } = props;
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);
  const [form, setForm] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || '',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light'
  });

  const update = (k: string, v: any) => setForm(p => ({ ...p, [k]: v }));
  const isEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const valid = step === 0 ? (form.name && isEmail(form.email) && form.avatar) : (step === 1 ? form.role : true);

  const progressPct = String(((step + 1) / 3) * 100) + '%';

  return (
    <Container maxWidth="sm">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
        <Stack gap={24}>
          <Stack gap={12}>
            <Text variant="h2" align="center">Setup Wizard</Text>
            <div style={{ height: 4, background: 'var(--ggui-color-neutral-100)', borderRadius: 4, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: progressPct, background: 'var(--ggui-color-primary-600)', transition: 'width 0.4s' }} />
            </div>
          </Stack>
          <div style={{ animation: motionEnabled ? animation.fadeIn : 'none', minHeight: 300 }}>
            {step === 0 && (
              <Stack gap={20}>
                <Input label="Name" value={form.name} onChange={(v) => update('name', v)} required />
                <Input label="Email" type="email" value={form.email} onChange={(v) => update('email', v)} required />
                <Stack gap={8}>
                  <Text variant="label">Select Avatar</Text>
                  <Row gap={12} justify="center">
                    {avatarOptions.map(a => (
                      <button key={a} onClick={() => update('avatar', a)} style={{ fontSize: 'var(--ggui-font-size-2xl)', padding: 12, borderRadius: 8, border: form.avatar === a ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)', background: form.avatar === a ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)', cursor: 'pointer' }}>{a}</button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}
            {step === 1 && (
              <Stack gap={20}>
                <Select label="Role" value={form.role} onChange={(v) => update('role', v)} options={roleOptions.map(r => ({ value: r, label: r }))} required />
                <Checkbox label="Email Notifications" checked={form.emailNotifications} onChange={(v) => update('emailNotifications', v)} description="Stay informed about updates" />
                <RadioGroup label="Theme" value={form.theme} onChange={(v) => update('theme', v)} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
              </Stack>
            )}
            {step === 2 && (
              <Stack gap={16}>
                <Text variant="h3">Review</Text>
                <Card variant="surfaceVariant" padding={16} border={false}>
                  <Stack gap={12}>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Profile</Text><Text weight="bold">{form.avatar} {form.name}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Email</Text><Text>{form.email}</Text></Row>
                    <Divider margin={8} />
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Role</Text><Text>{form.role}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Theme</Text><Text>{form.theme}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Alerts</Text><Text>{form.emailNotifications ? 'On' : 'Off'}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>
          <Divider />
          <Row justify="between">
            <Button variant="ghost" disabled={step === 0} onClick={() => setStep(step - 1)}>Go Back</Button>
            {step < 2 ? (
              <Button variant="primary" disabled={!valid} onClick={() => setStep(step + 1)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => complete(form)}>Complete Setup</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}
